        let token_amount = ctx.accounts.token_vault.amount;
        require!(sol_amount > 0, LaunchpadError::ZeroAmount);
        require!(token_amount > 0, LaunchpadError::ZeroAmount);

        let mint_key = ctx.accounts.mint.key();
