        curve.withdrawn_sol_amount = sol_amount;
        curve.withdrawn_token_amount = token_amount;
        curve.real_sol_reserves = 0;
        curve.real_token_reserves = 0;
        curve.migration_token_reserves = 0;
        curve.status = STATUS_ASSETS_WITHDRAWN;

